{"command": "tail -5 /root/projects/Codespace-3/sessions/6c6fce56-2524-46ce-bec6-0b80d6ab7879.jsonl | python3 -c "
import sys, json
for line in sys.stdin:
    try:
        obj = json.loads(line)
        if obj.get('type') == 'message':
            m = obj.get('message', {})
            role = m.get('role', '?')
            content = m.get('content', [])
            text_parts = [c.get('text','') for c in content if c.get('type')=='text']
            tool_calls = [c for c in content if c.get('type')=='toolCall']
            print(f'--- {role} ---')
            for t in text_parts:
                print(t[:300])
            for tc in tool_calls:
                print(f'  Tool: {tc.get(\"name\")}: {json.dumps(tc.get(\"arguments\",{}))[:200]}')
    except: pass
""}

