{"command": "tailscale status --json 2>/dev/null | python3 -c "
import sys, json
d = json.load(sys.stdin)
# Check if SSH is enabled
print('Tailscale SSH enabled:', d.get('SSH', 'unknown'))
# List peers with SSH info
for k, v in d.get('Peer', {}).items():
    if 'sgss' in v.get('HostName', '').lower() or 'sgss' in v.get('DNSName', '').lower():
        print(f'SGSS peer: {v.get(\"HostName\")} - SSH: {v.get(\"SSH_HostKeys\", \"no keys\")}')
""}

{"path": "/tmp/portfolio/cv.html", "content": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Walusimbi Leon — Curriculum Vitae</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,500;0,600;0,700;1,400;1,500&family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet">
<style>
:root {
  --gold: #c9a84c;
  --gold-light: #e8d5a3;
  --dark: #1a1a2e;
  --darker: #0f0f1a;
  --cream: #faf6ee;
  --text: #2d2d2d;
  --text-light: #6b6b6b;
  --text-muted: #999;
  --white: #ffffff;
  --border: #e0d8c8;
  --radius: 8px;
}
* { margin: 0; padding: 0; box-sizing: border-box; }
html { font-size: 15px; }
body {
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  background: #e8e4dc;
  color: var(--text);
  line-height: 1.6;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 40px 20px;
}

/* ─── Toolbar ─── */
.toolbar {
  width: 100%;
  max-width: 900px;
  display: flex;
  justify-content: flex-end;
  gap: 12px;
  margin-bottom: 20px;
}
.toolbar button {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 10px 20px;
  border: none;
  border-radius: 6px;
  font-family: 'Inter', sans-serif;
  font-size: 0.9em;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s;
}
.btn-download {
  background: var(--dark);
  color: var(--gold);
  border: 1px solid rgba(201,168,76,0.3);
}
.btn-download:hover { background: #2a2a4e; transform: translateY(-1px); }
.btn-back {
  background: transparent;
  color: var(--text-light);
  border: 1px solid var(--border);
}
.btn-back:hover { background: var(--cream); }

/* ─── CV Container ─── */
.cv-container {
  width: 100%;
  max-width: 900px;
  background: var(--white);
  border-radius: 12px;
  box-shadow: 0 10px 40px rgba(0,0,0,0.12);
  overflow: hidden;
}

/* ─── Header ─── */
.cv-header {
  background: linear-gradient(135deg, var(--darker) 0%, var(--dark) 100%);
  padding: 40px 50px;
  display: flex;
  gap: 40px;
  align-items: center;
  color: var(--white);
}
.cv-photo {
  width: 140px;
  height: 140px;
  border-radius: 50%;
  object-fit: cover;
  border: 3px solid var(--gold);
  flex-shrink: 0;
  background: #2a2a4e;
}
