  color: var(--text-dim);
  padding: 8px 12px;
  border-radius: 6px;
  cursor: pointer;
  font-size: 0.78em;
  text-align: left;
  transition: all 0.2s;
}
.preset-btn:hover {
  border-color: var(--gold);
  background: var(--gold-dim);
  color: var(--gold);
}

/* ───── Results ───── */
.results-area { min-height: 400px; }
.results-placeholder {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 400px;
  color: var(--text-muted);
  text-align: center;
  gap: 12px;
}
.results-placeholder .icon { font-size: 3em; }
.results-placeholder p { font-size: 0.9em; max-width: 300px; }

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 12px;
  margin-bottom: 20px;
}
.stat-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 14px;
  text-align: center;
}
.stat-card .stat-num {
  font-family: 'JetBrains Mono', monospace;
  font-size: 1.6em;
  font-weight: 700;
  color: var(--gold);
}
.stat-card .stat-num.win { color: var(--green); }
.stat-card .stat-num.loss { color: var(--red); }
.stat-card .stat-label {
  font-size: 0.72em;
  color: var(--text-dim);
  margin-top: 2px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* ───── Chart ───── */
.chart-container {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 16px;
  margin-bottom: 16px;
}
.chart-container canvas { width: 100% !important; }

/* ───── Pattern Matches Table ───── */
.matches-section { margin-top: 16px; }
.matches-section h4 {
  font-size: 0.85em;
  color: var(--text-dim);
  font-weight: 600;
  margin-bottom: 10px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
.matches-table-wrap {
  max-height: 350px;
  overflow-y: auto;
  border: 1px solid var(--border);
  border-radius: 6px;
}
table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.82em;
}
thead { position: sticky; top: 0; }
th {
  background: var(--surface);
  color: var(--text-dim);
  font-weight: 600;
  text-align: left;
  padding: 8px 10px;
  border-bottom: 1px solid var(--border);
  font-size: 0.78em;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
td {
  padding: 7px 10px;
  border-bottom: 1px solid rgba(42,42,80,0.5);
  font-family: 'JetBrains Mono', monospace;
  font-size: 0.82em;
}
tr:hover td { background: rgba(201,168,76,0.04); }
td.up { color: var(--green); }
td.down { color: var(--red); }
td .mini-bar {
  display: inline-block;
  width: 60px;
  height: 4px;
  border-radius: 2px;
  vertical-align: middle;
