}
.loading-bar.active { display: block; }
.loading-bar::after {
  content: '';
  display: block;
  width: 30%;
  height: 100%;
  background: var(--gold);
  border-radius: 2px;
  animation: loadSlide 1.2s ease-in-out infinite;
}
@keyframes loadSlide {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(400%); }
}

/* ───── Error ───── */
.error-banner {
  background: var(--red-dim);
  border: 1px solid rgba(239,68,68,0.3);
