<script>
// ═══════════════════════════════════════════════════
// STATE
// ═══════════════════════════════════════════════════
let conditions = [];
let candleData = [];
let analysisResult = null;
let counter = 0;

// ═══════════════════════════════════════════════════
// PATTERN PRESETS
// ═══════════════════════════════════════════════════
const PRESETS = {
  dip3: {
    conditions: [
      { field: 'close', op: 'decreaseN', value: 3, connector: 'then' },
      { field: 'close', op: 'increaseN', value: 1, connector: null }
    ]
  },
  pump3: {
    conditions: [
      { field: 'close', op: 'increaseN', value: 3, connector: 'then' },
      { field: 'close', op: 'decreaseN', value: 1, connector: null }
    ]
  },
  aboveSMA: {
    conditions: [
      { field: 'close', op: 'gt', value: 'sma_50', connector: 'then' },
      { field: 'close', op: 'increaseN', value: 1, connector: null }
    ]
  },
  volumeSpike: {
    conditions: [
      { field: 'volume', op: 'gt_avg2x', value: 0, connector: 'then' },
      { field: 'close', op: 'increaseN', value: 1, connector: null }
    ]
  },
  breakout: {
    conditions: [
      { field: 'close', op: 'gt_20d_high', value: 0, connector: 'then' },
      { field: 'close', op: 'increaseN', value: 2, connector: null }
    ]
  }
};

// ═══════════════════════════════════════════════════
// INIT
// ═══════════════════════════════════════════════════
function init() {
  // Start with one default condition
  conditions = [
    { field: 'close', op: 'decreaseN', value: 3, connector: 'then' },
    { field: 'close', op: 'increaseN', value: 1, connector: null }
  ];
  renderConditions();
  document.getElementById('addConditionBtn').addEventListener('click', addCondition);
  document.getElementById('analyzeBtn').addEventListener('click', runAnalysis);

  // Preset buttons
  document.querySelectorAll('.preset-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const preset = PRESETS[btn.dataset.preset];
      if (preset) {
        conditions = JSON.parse(JSON.stringify(preset.conditions));
        renderConditions();
      }
    });
  });

  // Enter key to analyze
  document.addEventListener('keydown', e => {
    if (e.key === 'Enter' && e.target.tagName !== 'TEXTAREA') {
      runAnalysis();
    }
  });
}

// ═══════════════════════════════════════════════════
// CONDITION RENDERER
// ═══════════════════════════════════════════════════
function addCondition() {
  conditions.push({ field: 'close', op: 'decreaseN', value: 1, connector: 'and' });
  renderConditions();
}

function removeCondition(idx) {
  if (conditions.length <= 1) return;
  conditions.splice(idx, 1);
  // Fix connectors
  if (conditions.length > 0) conditions[conditions.length - 1].connector = null;
  renderConditions();
}

function updateCondition(idx, key, val) {
  if (key === 'value') val = Number(val);
  conditions[idx][key] = val;
}

function renderConditions() {
  const container = document.getElementById('patternBuilder');
  container.innerHTML = '';

  conditions.forEach((cond, i) => {
    const block = document.createElement('div');
    block.className = 'condition-block';

    // Types of conditions
    const opOptions = [
      { value: 'increaseN', label: 'Increases for N days' },
      { value: 'decreaseN', label: 'Decreases for N days' },
      { value: 'gt', label: 'Greater than' },
      { value: 'lt', label: 'Less than' },
      { value: 'gte', label: '>= (gte)' },
      { value: 'lte', label: '<= (lte)' },
      { value: 'crossAbove', label: 'Crosses above' },
      { value: 'crossBelow', label: 'Crosses below' },
      { value: 'gt_pct', label: 'Up more than X%' },
      { value: 'lt_pct', label: 'Down more than X%' },
      { value: 'gt_avg2x', label: 'Volume > 2x avg' },
      { value: 'gt_20d_high', label: 'Above 20-day high' },
      { value: 'lt_20d_low', label: 'Below 20-day low' },
    ];

    const fieldOptions = [
      { value: 'close', label: 'Close' },
      { value: 'open', label: 'Open' },
      { value: 'high', label: 'High' },
      { value: 'low', label: 'Low' },
      { value: 'volume', label: 'Volume' },
    ];

    const needsValue = ['gt', 'lt', 'gte', 'lte', 'gt_pct', 'lt_pct', 'increaseN', 'decreaseN'];
    const valueIsPercent = ['gt_pct', 'lt_pct'];
    const valueIsDays = ['increaseN', 'decreaseN'];

    block.innerHTML = `
      <div class="cond-header">
        <span class="cond-type">Condition ${i + 1}</span>
        <button class="cond-remove" onclick="removeCondition(${i})">✕</button>
      </div>
      <div class="cond-row">
        <select onchange="updateCondition(${i},'field',this.value); renderConditions();">
          ${fieldOptions.map(o => `<option value="${o.value}" ${cond.field === o.value ? 'selected' : ''}>${o.label}</option>`).join('')}
        </select>
        <select onchange="updateCondition(${i},'op',this.value); renderConditions();">
          ${opOptions.map(o => `<option value="${o.value}" ${cond.op === o.value ? 'selected' : ''}>${o.label}</option>`).join('')}
        </select>
        ${needsValue.includes(cond.op) ? `
          <input type="number" value="${cond.value || 1}" min="1" onchange="updateCondition(${i},'value',this.value)" style="width:${valueIsDays.includes(cond.op) ? '50' : '70'}px">
          <span style="font-size:0.72em;color:var(--text-muted)">${valueIsPercent.includes(cond.op) ? '%' : valueIsDays.includes(cond.op) ? 'days' : ''}</span>
        ` : ''}
      </div>
    `;
    container.appendChild(block);

    // Connector (except for last)
    if (cond.connector) {
      const conn = document.createElement('div');
      conn.className = 'cond-connector';
      conn.innerHTML = `
        <select onchange="updateCondition(${i},'connector',this.value)" style="background:var(--surface);border:1px solid var(--border);color:var(--gold);padding:3px 8px;border-radius:4px;font-size:0.75em;font-weight:600;">
          <option value="and" ${cond.connector === 'and' ? 'selected' : ''}>AND</option>
          <option value="or" ${cond.connector === 'or' ? 'selected' : ''}>OR</option>
          <option value="then" ${cond.connector === 'then' ? 'selected' : ''}>THEN (sequential)</option>
        </select>
      `;
      container.appendChild(conn);
    }
  });
}

// ═══════════════════════════════════════════════════
// DATA FETCHING
// ═══════════════════════════════════════════════════
async function fetchData(symbol, interval, limit) {
  const url = `https://api.binance.com/api/v3/klines?symbol=${symbol}&interval=${interval}&limit=${limit}`;
  const resp = await fetch(url);
  if (!resp.ok) throw new Error(`Binance API error: ${resp.status}`);
  const data = await resp.json();

  return data.map(k => ({
    time: new Date(k[0]),
    open: parseFloat(k[1]),
    high: parseFloat(k[2]),
    low: parseFloat(k[3]),
    close: parseFloat(k[4]),
    volume: parseFloat(k[5]),
  }));
}

// ═══════════════════════════════════════════════════
// PATTERN ANALYSIS ENGINE
// ═══════════════════════════════════════════════════
function calcSMA(data, period) {
  const result = new Array(data.length).fill(null);
  for (let i = period - 1; i < data.length; i++) {
    let sum = 0;
    for (let j = 0; j < period; j++) sum += data[i - j].close;
    result[i] = sum / period;
  }
  return result;
}

function calcHighest(data, period, field = 'high') {
  const result = new Array(data.length).fill(null);
  for (let i = period - 1; i < data.length; i++) {
    let h = -Infinity;
    for (let j = 0; j < period; j++) if (data[i - j][field] > h) h = data[i - j][field];
    result[i] = h;
  }
  return result;
}

function calcLowest(data, period, field = 'low') {
  const result = new Array(data.length).fill(null);
  for (let i = period - 1; i < data.length; i++) {
    let l = Infinity;
    for (let j = 0; j < period; j++) if (data[i - j][field] < l) l = data[i - j][field];
    result[i] = l;
  }
  return result;
}

function evaluateCondition(data, idx, cond, sma50, sma200, avgVol, highest20, lowest20) {
  const c = data[idx];
  if (!c) return false;

  const field = cond.field;
  const val = cond.value || 1;
  const valNum = typeof val === 'number' ? val : parseFloat(val) || 1;

  // ── Compound indicators ──
  const sma50Val = sma50 ? sma50[idx] : null;
  const sma200Val = sma200 ? sma200[idx] : null;
  const avgVolVal = avgVol ? avgVol[idx] : null;
  const h20Val = highest20 ? highest20[idx] : null;
  const l20Val = lowest20 ? lowest20[idx] : null;

  switch (cond.op) {
    case 'increaseN': {
      if (idx < valNum) return false;
      for (let i = 0; i < valNum; i++) {
        if (!data[idx - i] || !data[idx - i - 1]) return false;
        if (data[idx - i][field] <= data[idx - i - 1][field]) return false;
      }
      return true;
    }
    case 'decreaseN': {
      if (idx < valNum) return false;
      for (let i = 0; i < valNum; i++) {
        if (!data[idx - i] || !data[idx - i - 1]) return false;
        if (data[idx - i][field] >= data[idx - i - 1][field]) return false;
      }
      return true;
    }
    case 'gt': return c[field] > (cond.value === 'sma_50' ? sma50Val : cond.value === 'sma_200' ? sma200Val : valNum);
    case 'lt': return c[field] < (cond.value === 'sma_50' ? sma50Val : cond.value === 'sma_200' ? sma200Val : valNum);
    case 'gte': return c[field] >= valNum;
    case 'lte': return c[field] <= valNum;
    case 'gt_avg2x': return avgVolVal > 0 && c.volume >= avgVolVal * 2;
    case 'gt_20d_high': return h20Val !== null && c.close >= h20Val;
    case 'lt_20d_low': return l20Val !== null && c.close <= l20Val;
    case 'gt_pct': {
      if (idx < 1) return false;
      const change = ((c[field] - data[idx - 1][field]) / data[idx - 1][field]) * 100;
      return change > valNum;
    }
    case 'lt_pct': {
      if (idx < 1) return false;
      const change = ((c[field] - data[idx - 1][field]) / data[idx - 1][field]) * 100;
      return change < -valNum;
    }
    case 'crossAbove': {
      if (idx < 1) return false;
      const ref = cond.value === 'sma_50' ? sma50Val : sma200Val;
      const refPrev = cond.value === 'sma_50' ? (sma50 ? sma50[idx - 1] : null) : (sma200 ? sma200[idx - 1] : null);
      if (ref === null || refPrev === null) return false;
      return data[idx - 1][field] <= refPrev && c[field] > ref;
    }
    case 'crossBelow': {
      if (idx < 1) return false;
      const ref2 = cond.value === 'sma_50' ? sma50Val : sma200Val;
      const refPrev2 = cond.value === 'sma_50' ? (sma50 ? sma50[idx - 1] : null) : (sma200 ? sma200[idx - 1] : null);
      if (ref2 === null || refPrev2 === null) return false;
      return data[idx - 1][field] >= refPrev2 && c[field] < ref2;
    }
    default: return false;
  }
}

function analyzePattern(data, conds) {
  if (!data || data.length < 20 || !conds || conds.length === 0) return null;

  // Precompute indicators
  const sma50 = calcSMA(data, 50);
  const sma200 = calcSMA(data, 200);
  const highest20 = calcHighest(data, 20, 'high');
  const lowest20 = calcLowest(data, 20, 'low');

  // Average volume (simple rolling 20-day)
  const avgVol = new Array(data.length).fill(null);
  for (let i = 19; i < data.length; i++) {
    let sum = 0;
    for (let j = 0; j < 20; j++) sum += data[i - j].volume;
    avgVol[i] = sum / 20;
  }

  // For "then" connector: condition B is evaluated on the candle AFTER condition A's match
  const matches = [];
  const thenGroups = [];
  let currentGroup = [];
  let hasThen = false;

  for (let i = 0; i < conds.length; i++) {
    currentGroup.push(conds[i]);
    if (conds[i].connector === 'then') {
      thenGroups.push([...currentGroup]);
      hasThen = true;
      currentGroup = [];
    }
  }
  if (currentGroup.length > 0) {
    thenGroups.push(currentGroup);
  }

  if (!hasThen) {
    // Simple AND/OR pattern — all conditions evaluated at the same candle
    const startIdx = data.length - 1;
    for (let i = Math.max(100, ...conds.map(c => c.op === 'increaseN' || c.op === 'decreaseN' ? Math.max(200, (c.value || 1) + 5) : 100)); i < data.length - 1; i++) {
      const results = conds.map(c => evaluateCondition(data, i, c, sma50, sma200, avgVol, highest20, lowest20));
      let match = false;
      // Walk through with connectors
      for (let j = 0; j < results.length; j++) {
        if (j === 0) {
          match = results[0];
        } else {
          const con = conds[j - 1].connector || 'and';
          if (con === 'and') match = match && results[j];
          else if (con === 'or') match = match || results[j];
        }
      }

      if (match) {
        const nextCandle = data[i + 1];
        const outcome = nextCandle ? ((nextCandle.close - nextCandle.open > 0) ? 'win' : 'loss') : '?';
        matches.push({
          date: data[i].time,
          close: data[i].close,
          nextClose: nextCandle ? nextCandle.close : null,
          nextChange: nextCandle ? ((nextCandle.close - data[i].close) / data[i].close * 100) : 0,
          outcome,
          index: i
        });
      }
    }
  } else {
    // THEN pattern — sequential conditions on sequential candles
    for (let i = Math.max(200, ...conds.map(c => (c.value || 1) * 2 + 20)); i < data.length - thenGroups.length; i++) {
      let offset = 0;
      let totalMatch = true;

      for (let g = 0; g < thenGroups.length; g++) {
        const group = thenGroups[g];
        const groupIdx = i + offset;
        if (groupIdx >= data.length) { totalMatch = false; break; }

        const results = group.map(c => evaluateCondition(data, groupIdx, c, sma50, sma200, avgVol, highest20, lowest20));

        let groupMatch = false;
        for (let j = 0; j < results.length; j++) {
          if (j === 0) groupMatch = results[0];
          else {
            const con = group[j - 1].connector || 'and';
            groupMatch = con === 'and' ? groupMatch && results[j] : groupMatch || results[j];
          }
        }

        if (!groupMatch) { totalMatch = false; break; }
        offset += 1; // Move to next candle for the next THEN group
      }

      if (totalMatch) {
        const outcomeIdx = i + offset;
        if (outcomeIdx < data.length) {
          const nextCandle = data[outcomeIdx];
          const prevCandle = data[outcomeIdx - 1];
          matches.push({
            date: data[i + thenGroups[0].length - 1].time,
            close: prevCandle ? prevCandle.close : data[i].close,
            nextClose: nextCandle.close,
            nextChange: prevCandle ? ((nextCandle.close - prevCandle.close) / prevCandle.close * 100) : 0,
            outcome: (nextCandle.close > nextCandle.open) ? 'win' : 'loss',
            index: i
          });
        }
      }
    }
  }

  // Stats
  const wins = matches.filter(m => m.outcome === 'win').length;
  const losses = matches.filter(m => m.outcome === 'loss').length;
  const total = wins + losses;

  return {
    totalOccurrences: matches.length,
    wins,
    losses,
    winRate: total > 0 ? (wins / total * 100) : 0,
    avgNextChange: matches.length > 0
      ? matches.reduce((s, m) => s + m.nextChange, 0) / matches.length
      : 0,
    bestWin: matches.length > 0 ? Math.max(...matches.map(m => m.nextChange)) : 0,
    worstLoss: matches.length > 0 ? Math.min(...matches.map(m => m.nextChange)) : 0,
    matches
  };
}

// ═══════════════════════════════════════════════════
// RESULTS RENDER
// ═══════════════════════════════════════════════════
function renderResults(result) {
  const container = document.getElementById('resultsContent');

  if (!result || result.totalOccurrences === 0) {
    container.innerHTML = `
      <div class="results-placeholder">
        <div class="icon">🔍</div>
        <p>No matches found. Try adjusting your pattern or using more data.</p>
      </div>
    `;
    return;
  }

  const m = result;

  container.innerHTML = `
    <!-- Stats -->
    <div class="stats-grid">
      <div class="stat-card">
        <div class="stat-num">${m.totalOccurrences}</div>
        <div class="stat-label">Pattern Matches</div>
      </div>
      <div class="stat-card">
        <div class="stat-num win">${m.wins}</div>
        <div class="stat-label">Wins (closed up)</div>
      </div>
      <div class="stat-card">
        <div class="stat-num loss">${m.losses}</div>
        <div class="stat-label">Losses (closed down)</div>
      </div>
      <div class="stat-card">
        <div class="stat-num ${m.winRate >= 50 ? 'win' : 'loss'}">${m.winRate.toFixed(1)}%</div>
        <div class="stat-label">Win Rate</div>
      </div>
      <div class="stat-card">
        <div class="stat-num ${m.avgNextChange >= 0 ? 'win' : 'loss'}">${m.avgNextChange >= 0 ? '+' : ''}${m.avgNextChange.toFixed(2)}%</div>
        <div class="stat-label">Avg Next Change</div>
      </div>
      <div class="stat-card">
        <div class="stat-num win">${m.bestWin >= 0 ? '+' : ''}${m.bestWin.toFixed(2)}%</div>
        <div class="stat-label">Best Outcome</div>
      </div>
    </div>

    <!-- Chart -->
    <div class="chart-container">
      <canvas id="resultChart"></canvas>
    </div>

    <!-- Matches Table -->
    <div class="matches-section">
      <h4>📋 Pattern Match Details (${m.matches.length} occurrences)</h4>
      <div class="matches-table-wrap">
        <table>
          <thead>
            <tr>
              <th>#</th>
              <th>Date</th>
              <th>Close at Pattern</th>
              <th>Next Close</th>
              <th>Change</th>
              <th>Outcome</th>
            </tr>
          </thead>
          <tbody>
            ${m.matches.slice(-100).reverse().map((match, idx) => `
              <tr>
                <td style="color:var(--text-muted)">${m.totalOccurrences - idx}</td>
                <td>${match.date.toISOString().split('T')[0]}</td>
                <td>$${match.close.toFixed(2)}</td>
                <td>${match.nextClose ? '$' + match.nextClose.toFixed(2) : '—'}</td>
                <td class="${match.nextChange >= 0 ? 'up' : 'down'}">
                  <span class="mini-bar" style="background:${match.nextChange >= 0 ? 'var(--green)' : 'var(--red)'};width:${Math.min(Math.abs(match.nextChange) * 3, 60)}px"></span>
                  ${match.nextChange >= 0 ? '+' : ''}${match.nextChange.toFixed(2)}%
                </td>
                <td class="${match.outcome === 'win' ? 'up' : 'loss'}">${match.outcome === 'win' ? '✅ WIN' : '❌ LOSS'}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>
      </div>
      ${m.matches.length > 100 ? `<div style="text-align:center;font-size:0.75em;color:var(--text-muted);margin-top:8px;">Showing last 100 of ${m.matches.length} matches</div>` : ''}
    </div>
  `;

  // Draw chart
  drawResultChart(m);
}

function drawResultChart(result) {
  const canvas = document.getElementById('resultChart');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const rect = canvas.parentElement.getBoundingClientRect();
  canvas.width = rect.width - 32;
  canvas.height = 280;

  const w = canvas.width;
  const h = canvas.height;
  const pad = { top: 20, bottom: 30, left: 10, right: 10 };

  // Aggregate by change buckets
  const changes = result.matches.map(m => m.nextChange).filter(c => !isNaN(c));
  if (changes.length === 0) return;

  const bucketCount = 20;
  const min = Math.min(...changes);
  const max = Math.max(...changes);
  const range = max - min || 1;
  const bucketSize = range / bucketCount;

  const buckets = new Array(bucketCount).fill(0);
  const bucketLabels = [];
  for (let i = 0; i < bucketCount; i++) {
    const lo = min + i * bucketSize;
    const hi = lo + bucketSize;
    bucketLabels.push(`${lo >= 0 ? '+' : ''}${lo.toFixed(1)}%`);
  }
  changes.forEach(c => {
    const idx = Math.min(bucketCount - 1, Math.floor((c - min) / bucketSize));
    buckets[idx]++;
  });

  const maxCount = Math.max(...buckets, 1);
  const barW = (w - pad.left - pad.right) / bucketCount;

  ctx.clearRect(0, 0, w, h);

  // Bars
  for (let i = 0; i < bucketCount; i++) {
    const x = pad.left + i * barW;
    const barH = (buckets[i] / maxCount) * (h - pad.top - pad.bottom);
    const y = h - pad.bottom - barH;
    const isPositive = (min + i * bucketSize) >= 0;

    // Gradient from red to green
    const ratio = i / (bucketCount - 1);
    const r = Math.round(239 - (239 - 34) * ratio);
    const g = Math.round(68 + (197 - 68) * ratio);
    const b = Math.round(68 - (68 - 94) * ratio);

    ctx.fillStyle = `rgba(${r},${g},${b},0.7)`;
    ctx.fillRect(x + 1, y, barW - 2, barH);

    // Border
    ctx.strokeStyle = `rgba(${r},${g},${b},0.3)`;
    ctx.lineWidth = 0.5;
    ctx.strokeRect(x + 1, y, barW - 2, barH);
  }

  // Labels
  ctx.fillStyle = 'var(--text-muted)';
  ctx.font = '10px Inter';
  ctx.textAlign = 'center';
  ctx.fillText(`${result.winRate.toFixed(0)}% win rate  •  ${result.totalOccurrences} occurrences  •  Avg ${result.avgNextChange >= 0 ? '+' : ''}${result.avgNextChange.toFixed(2)}%`, w / 2, h - 5);

  // Zero line
  const zeroRatio = (0 - min) / range;
  if (zeroRatio > 0 && zeroRatio < 1) {
    const zeroX = pad.left + zeroRatio * (w - pad.left - pad.right);
    ctx.strokeStyle = 'rgba(255,255,255,0.2)';
    ctx.lineWidth = 1;
    ctx.setLineDash([3, 3]);
    ctx.beginPath();
    ctx.moveTo(zeroX, pad.top);
    ctx.lineTo(zeroX, h - pad.bottom);
    ctx.stroke();
    ctx.setLineDash([]);
  }
}

// ═══════════════════════════════════════════════════
// MAIN ANALYSIS RUNNER
// ═══════════════════════════════════════════════════
async function runAnalysis() {
  const btn = document.getElementById('analyzeBtn');
  const loading = document.getElementById('loadingBar');
  const errorBanner = document.getElementById('errorBanner');
  const resultsContent = document.getElementById('resultsContent');

  errorBanner.classList.remove('show');
  errorBanner.textContent = '';
  btn.disabled = true;
  btn.textContent = '⏳ Fetching Data...';
  loading.classList.add('active');

  const symbol = document.getElementById('assetInput').value.trim().toUpperCase() || 'BTCUSDT';
  const interval = document.getElementById('intervalSelect').value;
  const limit = parseInt(document.getElementById('lookbackSelect').value) || 500;

  try {
    btn.textContent = '⏳ Fetching Data...';
    const data = await fetchData(symbol, interval, limit);
    candleData = data;

    btn.textContent = '⏳ Analyzing...';
    // Small delay for UI update
    await new Promise(r => setTimeout(r, 50));

    const result = analyzePattern(data, conditions);
    analysisResult = result;

    loading.classList.remove('active');

    if (!result) {
      resultsContent.innerHTML = `
        <div class="results-placeholder">
          <div class="icon">⚠️</div>
          <p>Could not analyze. Not enough data (need at least 200 candles).</p>
        </div>
      `;
      btn.disabled = false;
      btn.textContent = '🔍 Analyze Pattern';
      return;
    }

    renderResults(result);
    btn.disabled = false;
    btn.textContent = '🔍 Analyze Pattern';

  } catch (err) {
    loading.classList.remove('active');
    errorBanner.textContent = `❌ Error: ${err.message}`;
    errorBanner.classList.add('show');
    btn.disabled = false;
    btn.textContent = '🔍 Analyze Pattern';

    resultsContent.innerHTML = `
      <div class="results-placeholder">
        <div class="icon">⚠️</div>
        <p>Failed to fetch data. Check the asset symbol and try again.</p>
        <p style="font-size:0.78em;color:var(--text-muted)">${err.message}</p>
      </div>
    `;
  }
}

// ═══════════════════════════════════════════════════
// START
// ═══════════════════════════════════════════════════
init();
</script>

</body>
</html>
"}

