//+------------------------------------------------------------------+
//|                                                YouGamble1 EA.mq5 |
//|                                  Pattern-based Trading Expert     |
//|                        https://github.com/Walusimbi-Leon1/yougam |
//+------------------------------------------------------------------+
#property copyright "YouGamble1"
#property version   "1.00"
#property description "Pattern-based trading EA using YouGamble1 logic"
#property description "Select a pattern type and the EA trades when it detects it."

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>
#include <Trade\SymbolInfo.mqh>
#include <Trade\AccountInfo.mqh>

//+------------------------------------------------------------------+
//| ENUMERATIONS                                                      |
//+------------------------------------------------------------------+
enum ENUM_PATTERN_TYPE
{
   PAT_DIP_BOUNCE,   // Dip Bounce — Down N days, then up
   PAT_PUMP_DUMP,    // Pump Dump — Up N days, then down
   PAT_ABOVE_SMA,    // Above SMA — Close crosses above SMA-50
   PAT_BELOW_SMA,    // Below SMA — Close crosses below SMA-50
   PAT_VOLUME_SPIKE, // Volume Spike — Volume > 2x avg → direction
   PAT_BREAKOUT,     // Breakout — Close above 20-bar high
   PAT_BREAKDOWN,    // Breakdown — Close below 20-bar low
   PAT_ENGULFING     // Engulfing — Bullish/bearish engulfing
};

enum ENUM_TRADE_DIRECTION
{
   DIR_BOTH,  // Buy and Sell
   DIR_BUY,   // Buy only
   DIR_SELL   // Sell only
};

//+------------------------------------------------------------------+
//| INPUT PARAMETERS                                                  |
//+------------------------------------------------------------------+
input group "=== Pattern Settings ==="
input ENUM_PATTERN_TYPE    InpPatternType      = PAT_DIP_BOUNCE;      // Pattern Type
input int                  InpConsecutiveCandles = 3;                  // Consecutive candles (dip/pump)
input int                  InpLookbackBars     = 50;                   // Lookback bars (SMA, high/low)

input group "=== Trade Settings ==="
input ENUM_TRADE_DIRECTION InpDirection        = DIR_BOTH;            // Trade Direction
input double               InpLotSize          = 0.01;                // Lot Size
input int                  InpStopLossPips     = 200;                 // Stop Loss (points, 0=none)
input int                  InpTakeProfitPips   = 400;                 // Take Profit (points, 0=none)
input int                  InpMaxSpread        = 50;                   // Max Spread (points)
input int                  InpMagicNumber      = 2024001;              // Magic Number
input int                  InpMaxTradesPerDay  = 1;                    // Max Trades Per Day
input int                  InpSlippage         = 30;                   // Slippage (points)

input group "=== Risk Management ==="
input double               InpMaxRiskPercent   = 2.0;                 // Max Risk % per trade
input bool                 InpUseTrailingStop  = false;                // Use Trailing Stop
input int                  InpTrailingStart    = 100;                  // Trailing Start (points)
input int                  InpTrailingStep     = 30;                   // Trailing Step (points)

//+------------------------------------------------------------------+
//| GLOBALS                                                           |
//+------------------------------------------------------------------+
CTrade         m_trade;
CPositionInfo  m_position;
CSymbolInfo    m_symbol;
CAccountInfo   m_account;

datetime       m_lastBarTime  = 0;
int            m_handleSMA50  = INVALID_HANDLE;
double         m_smaBuffer[];

int            m_tradesToday  = 0;
datetime       m_tradeDate    = 0;
int            m_handleVolumeAvg = INVALID_HANDLE;
double         m_volBuffer[];

//+------------------------------------------------------------------+
//| Expert initialization function                                    |
//+------------------------------------------------------------------+
int OnInit()
{
   // Validate inputs
   if (InpLotSize <= 0) { Print("❌ Lot size must be positive"); return INIT_PARAMETERS_INCORRECT; }
   if (InpMaxTradesPerDay <= 0) { Print("❌ Max trades per day must be at least 1"); return INIT_PARAMETERS_INCORRECT; }
   if (InpConsecutiveCandles < 1 || InpConsecutiveCandles > 10) { Print("❌ Consecutive candles must be 1-10"); return INIT_PARAMETERS_INCORRECT; }
   if (InpLookbackBars < 20 || InpLookbackBars > 500) { Print("❌ Lookback bars must be 20-500"); return INIT_PARAMETERS_INCORRECT; }

   // Initialize symbol
   m_symbol.Name(Symbol());
   m_symbol.Refresh();

   // Initialize trade object
   m_trade.SetExpertMagicNumber(InpMagicNumber);
   m_trade.SetDeviationInPoints(InpSlippage);
   m_trade.SetAsyncMode(false);

   // Set up SMA handle (for SMA patterns)
   m_handleSMA50 = iMA(Symbol(), Period(), MathMin(InpLookbackBars, 50), 0, MODE_SMA, PRICE_CLOSE);
   if (m_handleSMA50 == INVALID_HANDLE) { Print("⚠️ Could not create SMA indicator handle"); }
   ArraySetAsSeries(m_smaBuffer, true);

   // Volume average handle
   m_handleVolumeAvg = iMA(Symbol(), Period(), 20, 0, MODE_SMA, PRICE_CLOSE);
   // We'll use volume via CopyClose and calculate manually

   Print("✅ YouGamble1 EA initialized — ", EnumToString(InpPatternType));
   Print("   Symbol: ", Symbol(), " | Timeframe: ", EnumToString(Period()));
   Print("   Direction: ", EnumToString(InpDirection), " | Lot: ", InpLotSize);

   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                  |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   if (m_handleSMA50 != INVALID_HANDLE) IndicatorRelease(m_handleSMA50);
   if (m_handleVolumeAvg != INVALID_HANDLE) IndicatorRelease(m_handleVolumeAvg);
   Print("🛑 YouGamble1 EA removed (reason: ", reason, ")");
}

//+------------------------------------------------------------------+
//| Expert tick function                                              |
//+------------------------------------------------------------------+
void OnTick()
{
   // ── Check if we have a new bar ──
   if (!IsNewBar()) return;

   // ── Refresh symbol data ──
   m_symbol.Refresh();
   m_symbol.RefreshRates();

   // ── Check spread ──
   double spread = m_symbol.Spread();
   if (spread > InpMaxSpread && InpMaxSpread > 0)
   {
      Print("⏸️ Spread too high: ", spread, " (max: ", InpMaxSpread, ")");
      return;
   }

   // ── Check daily trade limit ──
   CheckDailyLimit();
   if (m_tradesToday >= InpMaxTradesPerDay)
   {
      // Only log once per day
      static datetime lastLimitMsg = 0;
      if (lastLimitMsg != m_tradeDate) {
         Print("⏸️ Daily trade limit reached (", m_tradesToday, "/", InpMaxTradesPerDay, ")");
         lastLimitMsg = m_tradeDate;
      }
      return;
   }

   // ── Check existing positions ──
   if (HasPosition()) return;

   // ── Run pattern detection ──
   int signal = DetectPattern();
   if (signal == 0) return;

   // ── Execute trade ──
   ExecuteTrade(signal);
}

//+------------------------------------------------------------------+
//| Check if we have a new bar                                        |
//+------------------------------------------------------------------+
bool IsNewBar()
{
   datetime currentBarTime = iTime(Symbol(), Period(), 0);
   if (currentBarTime == 0) return false;

   if (m_lastBarTime != currentBarTime)
   {
      m_lastBarTime = currentBarTime;
      return true;
   }
   return false;
}

//+------------------------------------------------------------------+
//| Check daily trade limit                                           |
//+------------------------------------------------------------------+
void CheckDailyLimit()
{
   MqlDateTime dt;
   TimeCurrent(dt);
   datetime today = StructToTime(dt);

   if (today != m_tradeDate)
   {
      m_tradeDate = today;
      m_tradesToday = 0;
   }
}

//+------------------------------------------------------------------+
//| Check if there's already a position from this EA                  |
//+------------------------------------------------------------------+
bool HasPosition()
{
   for (int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if (m_position.SelectByIndex(i))
      {
         if (m_position.Symbol() == Symbol() && m_position.Magic() == InpMagicNumber)
            return true;
      }
   }
   return false;
}

//+------------------------------------------------------------------+
//| Main pattern detection engine                                     |
//+------------------------------------------------------------------+
int DetectPattern()
{
   int signal = 0;

   switch (InpPatternType)
   {
      case PAT_DIP_BOUNCE:    signal = DetectDipBounce();    break;
      case PAT_PUMP_DUMP:     signal = DetectPumpDump();     break;
      case PAT_ABOVE_SMA:     signal = DetectAboveSMA();     break;
      case PAT_BELOW_SMA:     signal = DetectBelowSMA();     break;
      case PAT_VOLUME_SPIKE:  signal = DetectVolumeSpike();  break;
      case PAT_BREAKOUT:      signal = DetectBreakout();     break;
      case PAT_BREAKDOWN:     signal = DetectBreakdown();    break;
      case PAT_ENGULFING:     signal = DetectEngulfing();    break;
   }

   // Apply direction filter
   if (signal == 1 && (InpDirection == DIR_SELL))  return 0;
   if (signal == -1 && (InpDirection == DIR_BUY))  return 0;

   if (signal != 0)
   {
      Print("🎯 Pattern detected! Signal: ", (signal > 0 ? "BUY" : "SELL"));
   }

   return signal;
}

//+------------------------------------------------------------------+
//| Dip Bounce: Close down N consecutive bars, then up                |
//+------------------------------------------------------------------+
int DetectDipBounce()
{
   int n = InpConsecutiveCandles;
   if (n < 1) return 0;

   // Check current bar (bar 0) for the bounce up
   if (iClose(Symbol(), Period(), 0) <= iOpen(Symbol(), Period(), 0))
      return 0; // Current bar must be bullish (the bounce)

   if (iClose(Symbol(), Period(), 0) <= iClose(Symbol(), Period(), 1))
      return 0; // Current close must be higher than previous close

   // Check bars 1 through N for consecutive down closes
   for (int i = 1; i <= n; i++)
   {
      if (iClose(Symbol(), Period(), i) >= iOpen(Symbol(), Period(), i))
         return 0; // Each bar in the dip must be bearish

      // Each bar must close lower than the previous
      if (iClose(Symbol(), Period(), i) >= iClose(Symbol(), Period(), i + 1))
         return 0;
   }

   return 1; // BUY signal
}

//+------------------------------------------------------------------+
//| Pump Dump: Close up N consecutive bars, then down                 |
//+------------------------------------------------------------------+
int DetectPumpDump()
{
   int n = InpConsecutiveCandles;
   if (n < 1) return 0;

   // Current bar must be bearish (the dump)
   if (iClose(Symbol(), Period(), 0) >= iOpen(Symbol(), Period(), 0))
      return 0;

   if (iClose(Symbol(), Period(), 0) >= iClose(Symbol(), Period(), 1))
      return 0;

   // Check bars 1 through N for consecutive up closes
   for (int i = 1; i <= n; i++)
   {
      if (iClose(Symbol(), Period(), i) <= iOpen(Symbol(), Period(), i))
         return 0;

      if (iClose(Symbol(), Period(), i) <= iClose(Symbol(), Period(), i + 1))
         return 0;
   }

   return -1; // SELL signal
}

//+------------------------------------------------------------------+
//| Above SMA: Close crosses above SMA-50                             |
//+------------------------------------------------------------------+
int DetectAboveSMA()
{
   if (m_handleSMA50 == INVALID_HANDLE) return 0;

   int copied = CopyBuffer(m_handleSMA50, 0, 0, 3, m_smaBuffer);
   if (copied < 3) return 0;

   double close0 = iClose(Symbol(), Period(), 0);
   double close1 = iClose(Symbol(), Period(), 1);

   if (close0 > m_smaBuffer[0] && close1 <= m_smaBuffer[1])
      return 1; // Cross above → BUY

   return 0;
}

//+------------------------------------------------------------------+
//| Below SMA: Close crosses below SMA-50                             |
//+------------------------------------------------------------------+
int DetectBelowSMA()
{
   if (m_handleSMA50 == INVALID_HANDLE) return 0;

   int copied = CopyBuffer(m_handleSMA50, 0, 0, 3, m_smaBuffer);
   if (copied < 3) return 0;

   double close0 = iClose(Symbol(), Period(), 0);
   double close1 = iClose(Symbol(), Period(), 1);

   if (close0 < m_smaBuffer[0] && close1 >= m_smaBuffer[1])
      return -1; // Cross below → SELL

   return 0;
}

//+------------------------------------------------------------------+
//| Volume Spike: Volume > 2x average → follow direction              |
//+------------------------------------------------------------------+
int DetectVolumeSpike()
{
   // Get volume data for last 21 bars (20 for avg + current)
   double volumes[];
   ArraySetAsSeries(volumes, true);
   int copied = CopyTickVolume(Symbol(), Period(), 0, 21, volumes);
   if (copied < 21) return 0;

   // Calculate average volume of last 20 bars (excluding current)
   double avgVol = 0;
   for (int i = 1; i < 21; i++) avgVol += volumes[i];
   avgVol /= 20;

   // Check if current volume is at least 2x average
   if (avgVol <= 0) return 0;
   if (volumes[0] < avgVol * 2.0) return 0;

   // Signal in the direction of the current candle
   if (iClose(Symbol(), Period(), 0) > iOpen(Symbol(), Period(), 0))
      return 1; // Bullish on volume spike → BUY
   else
      return -1; // Bearish on volume spike → SELL
}

//+------------------------------------------------------------------+
//| Breakout: Close above N-bar high                                  |
//+------------------------------------------------------------------+
int DetectBreakout()
{
   int bars = MathMax(20, InpLookbackBars);

   double highs[];
   ArraySetAsSeries(highs, true);
   int copied = CopyHigh(Symbol(), Period(), 1, bars, highs);
   if (copied < bars) return 0;

   double currentHigh = iHigh(Symbol(), Period(), 0);
   double highestPrev = highs[ArrayMaximum(highs, 0, bars)];

   if (currentHigh > highestPrev)
      return 1; // Breakout above highest high → BUY

   return 0;
}

//+------------------------------------------------------------------+
//| Breakdown: Close below N-bar low                                  |
//+------------------------------------------------------------------+
int DetectBreakdown()
{
   int bars = MathMax(20, InpLookbackBars);

   double lows[];
   ArraySetAsSeries(lows, true);
   int copied = CopyLow(Symbol(), Period(), 1, bars, lows);
   if (copied < bars) return 0;

   double currentLow = iLow(Symbol(), Period(), 0);
   double lowestPrev = lows[ArrayMinimum(lows, 0, bars)];

   if (currentLow < lowestPrev)
      return -1; // Breakdown below lowest low → SELL

   return 0;
}

//+------------------------------------------------------------------+
//| Engulfing Pattern                                                 |
//+------------------------------------------------------------------+
int DetectEngulfing()
{
   double open0  = iOpen(Symbol(), Period(), 0);
   double close0 = iClose(Symbol(), Period(), 0);
   double open1  = iOpen(Symbol(), Period(), 1);
   double close1 = iClose(Symbol(), Period(), 1);

   bool bear1 = close1 < open1;  // Previous bar was bearish
   bool bull1 = close1 > open1;  // Previous bar was bullish

   // Bullish engulfing: bearish previous bar, current bar completely engulfs it
   if (bear1 && open0 < close1 && close0 > open1)
      return 1;

   // Bearish engulfing: bullish previous bar, current bar completely engulfs it
   if (bull1 && open0 > close1 && close0 < open1)
      return -1;

   return 0;
}

//+------------------------------------------------------------------+
//| Calculate lot size based on risk management                       |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   double lot = InpLotSize;

   // Check if risk-based sizing is applicable
   if (InpMaxRiskPercent > 0 && InpStopLossPips > 0)
   {
      double tickValue = m_symbol.TickValue();
      double tickSize  = m_symbol.TickSize();
      double point     = m_symbol.Point();

      if (tickValue > 0 && tickSize > 0)
      {
         // Calculate stop loss in price units
         double slPoints = InpStopLossPips * m_symbol.Point();
         if (slPoints > 0)
         {
            double riskAmount = m_account.Balance() * (InpMaxRiskPercent / 100.0);
            double riskPerLot = (slPoints / tickSize) * tickValue;
            if (riskPerLot > 0)
            {
               double riskLot = riskAmount / riskPerLot;
               lot = MathMin(lot, riskLot);

               // Round down to lot step
               double lotStep = m_symbol.LotStep();
               if (lotStep > 0)
                  lot = MathFloor(lot / lotStep) * lotStep;

               // Clamp to min/max
               lot = MathMax(lot, m_symbol.LotsMin());
               lot = MathMin(lot, m_symbol.LotsMax());
            }
         }
      }
   }

   return lot;
}

//+------------------------------------------------------------------+
//| Execute a trade                                                   |
//+------------------------------------------------------------------+
void ExecuteTrade(int signal)
{
   if (signal == 0) return;

   double price, sl, tp;

   m_symbol.RefreshRates();
   double point   = m_symbol.Point();
   double bid     = m_symbol.Bid();
   double ask     = m_symbol.Ask();

   if (InpDirection == DIR_BUY || (InpDirection == DIR_BOTH && signal > 0))
   {
      price = m_symbol.Ask();
      sl = (InpStopLossPips > 0) ? price - InpStopLossPips * point : 0;
      tp = (InpTakeProfitPips > 0) ? price + InpTakeProfitPips * point : 0;

      double lot = CalculateLotSize();

      if (m_trade.Buy(lot, Symbol(), price, sl, tp, "YG1"))
      {
         m_tradesToday++;
         Print("✅ BUY opened — Lot: ", lot, " | Price: ", price, " | SL: ", sl, " | TP: ", tp);
      }
      else
      {
         Print("❌ BUY failed — Error: ", GetLastError());
      }
   }
   else if (InpDirection == DIR_SELL || (InpDirection == DIR_BOTH && signal < 0))
   {
      price = m_symbol.Bid();
      sl = (InpStopLossPips > 0) ? price + InpStopLossPips * point : 0;
      tp = (InpTakeProfitPips > 0) ? price - InpTakeProfitPips * point : 0;

      double lot = CalculateLotSize();

      if (m_trade.Sell(lot, Symbol(), price, sl, tp, "YG1"))
      {
         m_tradesToday++;
         Print("✅ SELL opened — Lot: ", lot, " | Price: ", price, " | SL: ", sl, " | TP: ", tp);
      }
      else
      {
         Print("❌ SELL failed — Error: ", GetLastError());
      }
   }
}

//+------------------------------------------------------------------+
//| Trailing stop management (called on every tick)                   |
//+------------------------------------------------------------------+
void CheckTrailingStop()
{
   if (!InpUseTrailingStop) return;
   if (InpTrailingStart <= 0) return;

   for (int i = PositionsTotal() - 1; i >= 0; i--)
   {
